      "content": "const { randomUUID } = require('node:crypto');

let tasksStore = {};

function addTask(projectId, taskData) {
  if (!tasksStore[projectId]) {
    tasksStore[projectId] = [];
  }
  const newTask = { id: randomUUID(), ...taskData, status: 'todo' };
  tasksStore[projectId].push(newTask);
  return newTask;
}

function getTasksByProjectId(projectId) {
  return tasksStore[projectId] || [];
}

module.exports = { addTask, getTasksByProjectId };
